const body = $input.first().json.body || {};

if (body.type === 'url_verification' && body.challenge) {
  return [{ json: { mode: 'challenge', challenge: body.challenge } }];
}

const event = body.event || {};
if (event.bot_id || event.subtype === 'bot_message') return [];

const text = event.text || '';
const isMention = text.includes('<@');
if (!event.thread_ts && !isMention) return [];

return [{
  json: {
    mode: 'event',
    channel: event.channel,
    thread_ts: event.thread_ts || event.ts,
    ts: event.ts || event.thread_ts,
    text,
    user: event.user || '',
    is_mention: isMention
  }
}];

if ($json.mode !== 'event') return [];

const channel = $json.channel;
const text = ($json.text || '').toLowerCase();
const isDecision = channel === 'C0AM2310P8A' && /(log this|decided:)/i.test(text);

const channelPersonaMap = {
  C0ALLEKR9FZ: { name: 'Engineering', icon: ':gear:', prompt: 'You are the Staff Engineer persona for Paperwork Labs. Give practical implementation guidance, call out risks, and keep answers concise. If reviewing a PR, include risks and test recommendations.' },
  C0ALLJWR1HV: { name: 'EA / Operator', icon: ':clipboard:', prompt: 'You are the EA / Operator persona for Paperwork Labs. Provide clear operational guidance and next actions.' },
  C0AM2310P8A: { name: 'Strategy', icon: ':chess_pawn:', prompt: 'You are the Strategy persona for Paperwork Labs. Focus on tradeoffs, prioritization, and milestone alignment.' },
  C0ALLD3P3A9: { name: 'QA', icon: ':shield:', prompt: 'You are the QA persona for Paperwork Labs. Focus on bugs, regressions, testing gaps, and security risks.' },
  C0AMEQV199P: { name: 'Strategy', icon: ':chess_pawn:', prompt: 'You are the Strategy persona for Paperwork Labs. Focus on high-leverage priorities and company-level execution.' },
  C0AM01NHQ3Y: { name: 'Engineering', icon: ':gear:', prompt: 'You are the Engineering persona for Paperwork Labs. Provide technically sound, executable guidance.' },
};

const intentPersonas = [
  { id: 'legal', regex: /(^|\b)(@?legal|counsel|compliance review|legal review)(\b|$)/i, persona: { name: 'Legal', icon: ':scroll:', prompt: 'You are General Counsel for Paperwork Labs. Focus on legal risk, compliance boundaries, disclosures, and policy implications. Keep advice practical and concrete.' } },
  { id: 'social', regex: /(^|\b)(@?social|social take|content angle|creator)(\b|$)/i, persona: { name: 'Social', icon: ':speech_balloon:', prompt: 'You are the Social persona for Paperwork Labs. Give distribution-focused messaging guidance, hooks, and concise copy edits.' } },
  { id: 'growth', regex: /(^|\b)(@?growth|growth take|acquisition|seo|funnel)(\b|$)/i, persona: { name: 'Growth', icon: ':rocket:', prompt: 'You are the Growth persona for Paperwork Labs. Focus on activation, acquisition, conversion, and measurable growth experiments.' } },
  { id: 'qa', regex: /(^|\b)(@?qa|test|testing|regression|security scan)(\b|$)/i, persona: { name: 'QA', icon: ':shield:', prompt: 'You are the QA persona for Paperwork Labs. Prioritize defects, regressions, missing test coverage, and security checks.' } },
  { id: 'strategy', regex: /(^|\b)(@?strategy|priorit|roadmap|tradeoff|exec)(\b|$)/i, persona: { name: 'Strategy', icon: ':chess_pawn:', prompt: 'You are the Strategy persona for Paperwork Labs. Focus on sequencing, tradeoffs, and venture-level alignment.' } },
  { id: 'engineering', regex: /(^|\b)(@?engineering|@?eng|implementation|architecture|code review)(\b|$)/i, persona: { name: 'Engineering', icon: ':gear:', prompt: 'You are the Staff Engineer persona for Paperwork Labs. Give direct implementation guidance, code-level risk review, and testing recommendations.' } },
  { id: 'cpa', regex: /(^|\b)(@?cpa|tax advisor|tax review)(\b|$)/i, persona: { name: 'CPA Advisor', icon: ':bar_chart:', prompt: 'You are the CPA / Tax Advisor persona for Paperwork Labs. Focus on tax accuracy, edge cases, and safe user-facing guidance.' } },
  { id: 'partnerships', regex: /(^|\b)(@?partnerships|partner|affiliate|bd)(\b|$)/i, persona: { name: 'Partnerships', icon: ':handshake:', prompt: 'You are the Partnerships persona for Paperwork Labs. Focus on partner fit, outreach posture, and commercial implications.' } },
  { id: 'ea', regex: /(^|\b)(@?ea|operator|ops view|briefing)(\b|$)/i, persona: { name: 'EA / Operator', icon: ':clipboard:', prompt: 'You are the EA / Operator persona for Paperwork Labs. Focus on execution clarity, owner/action mapping, and operational cadence.' } }
];

const override = intentPersonas.find((entry) => entry.regex.test(text));
const defaultPersona = channelPersonaMap[channel] || channelPersonaMap.C0AM01NHQ3Y;
const persona = override ? override.persona : defaultPersona;

return [{
  json: {
    ...$json,
    route: isDecision ? 'decision' : 'reply',
    persona_name: persona.name,
    persona_icon: persona.icon,
    persona_prompt: persona.prompt,
    persona_override: override ? override.id : null
  }
}];

const routed = $('Route Persona').first().json;
const thread = $('Fetch Thread History').first().json;
const messages = (thread.messages || []).slice(-20).map((m) => `${m.user || 'bot'}: ${m.text || ''}`).join('\n');

const userPrompt = `Channel: ${routed.channel}\nThread TS: ${routed.thread_ts}\nLatest message: ${routed.text}\n\nRecent thread context:\n${messages}\n\nRespond in Slack-ready markdown. Keep it concise and actionable.`;

return [{
  json: {
    channel: routed.channel,
    thread_ts: routed.thread_ts,
    persona_name: routed.persona_name,
    persona_icon: routed.persona_icon,
    system_prompt: routed.persona_prompt,
    user_prompt: userPrompt
  }
}];

const routed = $('Build Thread Context').first().json;
const output = $json.output || [];
const aiText = output[0]?.content?.find((part) => part.type === 'output_text')?.text;

const errorMessage = (
  $json.error?.message ||
  $json.error?.description ||
  $json.message ||
  ''
);

let text = aiText;
if (!text) {
  const err = String(errorMessage).toLowerCase();

  if (err.includes('insufficient_quota') || err.includes('exceeded your current quota')) {
    text = ':warning: AI response unavailable: OpenAI quota is exhausted for this workspace. Please top up billing, then retry this thread message.';
  } else if (err.includes('rate') || err.includes('429')) {
    text = ':warning: AI response unavailable: OpenAI rate limit hit. Please retry in 30-60 seconds.';
  } else if (err.includes('incorrect api key') || err.includes('invalid_api_key') || err.includes('unauthorized') || err.includes('401')) {
    text = ':warning: AI response unavailable: OpenAI credential is invalid. Please update the n8n OpenAI credential and retry.';
  } else {
    text = ':warning: AI response unavailable right now. Most likely cause is model quota or billing limits. Please top up/check OpenAI billing, then retry this thread.';
  }
}

return [{
  json: {
    channel: routed.channel,
    thread_ts: routed.thread_ts,
    text,
    username: routed.persona_name,
    icon_emoji: routed.persona_icon
  }
}];
